jQuery(function($){'use strict';var renewals_field=document.querySelector('.wcs_number_payments_field'),$renewals_field=$(renewals_field);var wcs_meta_boxes_coupon_actions={init:function(){if(renewals_field){$(document.getElementById('discount_type')).on('change',this.type_options).trigger('change');this.move_field();}},type_options:function(){var select_val=$(this).val();switch(select_val){case'recurring_fee':case'recurring_percent':$renewals_field.show();break;default:$renewals_field.hide();break;}},move_field:function(){var parent=document.getElementById('general_coupon_data'),shipping=parent.querySelector('.free_shipping_field');parent.insertBefore(renewals_field,shipping);},};wcs_meta_boxes_coupon_actions.init();});